\end{center}

\vspace{3mm}
{\Large \bfseries \color{zfblue} Vodiče a izolanty}
\vspace{2mm}

\begin{itemize}
    \item \textbf{Vodiče} -- náboj jimi snadno prochází (kovy, voda s rozpuštěnou solí).
    \item \textbf{Izolanty} (nevodiče) -- náboj jimi neprochází (plast, sklo, guma, suché dřevo).
\end{itemize}

